                        <div className="z-10">
                            <div className="flex items-center gap-1.5 mb-1">
                                <Star size={12} className="text-white fill-white drop-shadow" />
                                <p className="text-[10px] font-black text-white/90 uppercase tracking-widest">Efficiency Tier</p>
                            </div>
                            <h3 className="text-2xl font-black text-white leading-tight uppercase tracking-tighter drop-shadow">
                                {miningTierInfo?.name || 'Novice'}
                            </h3>
                        </div>
                        <div className="z-10 space-y-2">
                            <div className="flex justify-between items-end">
                                <span className="text-[8px] font-black text-white/80 uppercase">Progress</span>
                                <span className="text-[10px] font-black text-white">{miningTierInfo?.progress.toFixed(0)}%</span>
                            </div>
                            <ZigzagLine progress={miningTierInfo?.progress || 0} variant="gold" />
                            <div className="flex items-center gap-1 text-[8px] text-white/80 font-black uppercase tracking-widest mt-1">
                                View Tiers <ChevronRight size={10} />
                            </div>
                        </div>
                    </button>
                </div>

                {/* Box 4: Interactive Mining Terminal */}
                <div className="bg-brand-gray-50 dark:bg-brand-gray-900 rounded-[3rem] p-9 border border-brand-gray-100 dark:border-brand-gray-800 relative overflow-hidden shadow-2xl">
                    <div className="flex flex-col items-center text-center space-y-10">

                        {/* Unique Animated Globe Visual */}
                        <div className="relative">
                            <div className="absolute inset-0 bg-[#5839FF]/10 blur-[100px] rounded-full scale-150"></div>
                            <div className="relative z-10 flex flex-col items-center">
                                <div className="relative w-72 h-72 flex items-center justify-center">
                                    {/* Rotating Ring */}
                                    <div className={`absolute inset-0 rounded-full border-4 border-dashed border-[#5839FF]/20 ${isMining ? 'animate-spin-slow' : 'opacity-20'}`}></div>
                                    <div className={`absolute inset-4 rounded-full border border-[#5839FF]/10 ${isMining ? 'animate-spin' : 'opacity-10'}`} style={{ animationDirection: 'reverse', animationDuration: '10s' }}></div>

                                    {/* Central Hub - BIG LOGO */}
                                    <div className={`relative z-10 w-48 h-48 bg-white dark:bg-brand-gray-800 rounded-full p-10 shadow-2xl border border-brand-gray-100 dark:border-brand-gray-700 flex items-center justify-center transform transition-all duration-1000 ${isMining ? 'scale-110 shadow-[#5839FF]/30' : 'grayscale brightness-75 rotate-12 opacity-50'}`}>
                                        <Logo className={`w-full h-full object-contain ${isMining ? 'animate-pulse' : ''}`} />
                                    </div>

                                    {/* Orbiting Widgets */}
                                    <div className={`absolute top-4 right-4 w-16 h-16 rounded-full bg-[#5839FF] shadow-lg flex items-center justify-center text-white transition-all duration-700 ${isMining ? 'scale-100' : 'scale-0'}`}>
                                        <Zap size={28} className="fill-white" />
                                    </div>
                                    <div className={`absolute bottom-4 left-4 w-14 h-14 rounded-2xl bg-white dark:bg-brand-gray-800 shadow-md flex items-center justify-center border border-brand-gray-100 dark:border-brand-gray-700 transition-all duration-700 ${isMining ? 'scale-100' : 'scale-0'}`}>
                                        <ShieldCheck size={24} className="text-green-500" />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-1">
                            <h2 className="text-3xl font-black text-brand-gray-900 dark:text-white uppercase tracking-tight">Mining Terminal</h2>
                            <p className="text-xs text-brand-gray-400 font-medium max-w-[280px] mx-auto opacity-70 italic leading-relaxed">Global consensus protocol initiated.</p>
                        </div>

                        {isMining && (
                            <div className="w-full space-y-8 pt-2">
                                <WavyProgress isMining={isMining} progress={miningProgress} />

                                <div className="flex items-center justify-between px-8 py-6 bg-white dark:bg-brand-gray-800 rounded-[2.5rem] shadow-lg border border-brand-gray-100 dark:border-brand-gray-700">
                                    <div className="text-left">
                                        <p className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">Session Ends In</p>
                                        <div className="flex items-center gap-2">
                                            <div className="w-2 h-2 rounded-full bg-[#5839FF] animate-ping"></div>
                                            <p className="text-2xl font-black text-brand-gray-900 dark:text-white tabular-nums tracking-wider">
                                                {String(hours).padStart(2, '0')}:{String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-end">
                                        <p className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">Status</p>
                                        <span className="text-[10px] font-black text-green-500 bg-green-500/10 px-4 py-1.5 rounded-full uppercase tracking-tighter">Active Node</span>
                                    </div>
                                </div>

                                {/* Rate Breakdown */}
                                <div className="grid grid-cols-3 gap-3 px-1">
                                    <div className="p-4 bg-brand-gray-100/50 dark:bg-brand-gray-800/50 rounded-2xl border border-transparent transition-all hover:bg-white dark:hover:bg-brand-gray-800 shadow-sm">
                                        <p className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">Base</p>
                                        <p className="text-md font-black text-brand-gray-900 dark:text-white">{baseMiningRate.toFixed(2)}</p>
                                    </div>
                                    <div className="p-4 bg-brand-gray-100/50 dark:bg-brand-gray-800/50 rounded-2xl border border-transparent transition-all hover:bg-white dark:hover:bg-brand-gray-800 shadow-sm">
                                        <p className="text-[9px] font-black text-brand-gray-400 uppercase tracking-widest mb-1">Referral</p>
                                        <p className="text-md font-black text-indigo-500">+{referralMiningRate.toFixed(2)}</p>
                                    </div>
                                    <div className="p-4 bg-[#5839FF]/5 dark:bg-[#5839FF]/10 rounded-2xl border border-[#5839FF]/30 scale-105 shadow-xl shadow-[#5839FF]/10">
                                        <p className="text-[9px] font-black text-[#5839FF] uppercase tracking-widest mb-1">Total</p>
                                        <p className="text-md font-black text-[#5839FF]">{totalMiningRate.toFixed(2)}</p>
                                    </div>
                                </div>
                            </div>
                        )}

                        <div className="pt-2 w-full">
                            <button 
                                onClick={startMining}
                                disabled={isMining}
                                className={`w-full py-6 rounded-[2.5rem] font-black text-xl tracking-[0.2em] transition-all flex items-center justify-center gap-3 shadow-2xl relative overflow-hidden group ${isMining ? 'bg-brand-gray-100 dark:bg-brand-gray-800 text-brand-gray-400 cursor-default' : 'bg-[#5839FF] text-white active:scale-95 shadow-[#5839FF]/40 border-b-4 border-b-[#4429E6] active:translate-y-1 active:border-b-0'}`}
                            >
                                <span className="relative z-10">{isMining ? 'SYNTHESIS ACTIVE' : 'ACTIVATE TERMINAL'}</span>
                                {!isMining && <ArrowUpRight size={24} className="relative z-10 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />}
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            {/* Daily Loyalty Trigger */}
            <button 
                onClick={() => setIsBonusOpen(true)}
                className="fixed bottom-28 right-6 w-16 h-16 bg-white dark:bg-brand-gray-900 rounded-[2rem] shadow-2xl border-2 border-brand-gray-100 dark:border-brand-gray-800 flex items-center justify-center text-[#5839FF] group transition-all active:scale-90 z-[90] hover:border-[#5839FF]/50 hover:scale-110"
            >
                <div className="relative">
                    <Calendar size={30} strokeWidth={2.5} />
                    {canCheckIn() && <span className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-red-500 rounded-full border-2 border-white dark:border-brand-gray-900 animate-pulse shadow-lg flex items-center justify-center text-[10px] font-black text-white">!</span>}
                </div>
            </button>
        </div>
    );
};

export default HomePage;
